import { llamaApiCall } from "../llm/llm.llama.js";
import { geminiApiCall } from "../llm/llm.gemini.js"
import { openAiApiCall } from "../llm/llm.openai.js";

export async function anaylsisServices(params) {
  //taking all the data generated by artificial intelligence #tip : use Promise.all() to run
  //all three at once
  const dataFromLlamaAI = await llamaApiCall(params);
  const dataFromGeminiAI = await geminiApiCall(params);
  const dataFromOpenAI = await openAiApiCall(params);

  console.log("This is response from Llama : \n", dataFromLlamaAI);
  console.log("\n\nThis is response from Gemini : \n", dataFromGeminiAI);
  console.log("\n\nThis is response from Gpt Oss : \n", dataFromOpenAI);
}
